// Routage des appels IA : relais serveur en production (clé API protégée côté serveur),
// appel direct proxifié dans l'aperçu Claude. Le jeton Clerk est joint pour que le relais l'authentifie.
const CLAUDE_URL = (() => {
  try { const h = (typeof window !== "undefined" && window.location && window.location.hostname) || ""; if (/claude\.ai$|usercontent|anthropic/i.test(h)) return "https://api.anthropic.com/v1/messages"; } catch (e) {}
  return "/api/claude";
})();
async function claudeHeaders() {
  const h = { "Content-Type": "application/json" };
  try { if (typeof window !== "undefined" && window.__getClerkToken) { const t = await window.__getClerkToken(); if (t) h["Authorization"] = "Bearer " + t; } } catch (e) {}
  return h;
}

// Lecture du stock Shopify via le relais serveur /api/shopify (token Admin protege cote serveur).
// action « test » : verifie la connexion. action « sync » : renvoie les variantes (SKU + quantite).
async function shopifyApi(action) {
  const res = await fetch("/api/shopify", { method: "POST", headers: await claudeHeaders(), body: JSON.stringify({ action }) });
  let dt = {}; try { dt = await res.json(); } catch (e) {}
  if (!res.ok) throw new Error((dt && dt.error) ? dt.error : ("Erreur Shopify (" + res.status + ")"));
  return dt;
}

// Rapproche les variantes Shopify (par SKU) avec le catalogue MITMIT (par code).
// Renvoie un patch { code: dispo } et le nombre de references appariees.
function shopifyStockPatch(products, variants) {
  const bySku = {};
  (variants || []).forEach((v) => { if (v && v.sku) bySku[String(v.sku).trim().toLowerCase()] = v; });
  const patch = {}; let matched = 0;
  (products || []).forEach((p) => {
    const v = bySku[String(p.code || "").trim().toLowerCase()];
    if (v && v.dispo != null && !isNaN(v.dispo)) { patch[p.code] = Math.max(0, Math.round(v.dispo)); matched++; }
  });
  return { patch, matched };
}

