const DEAL_STATUS = { brouillon: { label: "Brouillon", color: "#9aa6bd" }, envoye: { label: "Envoyé", color: "#5b8def" }, accepte: { label: "Accepté / Signé", color: "#2bb673" }, expediee: { label: "En cours de livraison", color: "#F8B133" }, refuse: { label: "Refusé", color: "#FF5A45" }, livre: { label: "Livré", color: "#3F60AA" } };
// Devis non validé (brouillon ou envoyé) → alimente le « CA HT en attente ». Document signé → « CA HT signé ».
const isDevisEnAttente = (d) => d && d.type === "Devis" && (d.statut === "brouillon" || d.statut === "envoye");
const isCaSigne = (d) => d && (d.statut === "accepte" || d.statut === "expediee" || d.statut === "livre");
const sumMontant = (arr) => (arr || []).reduce((s, d) => s + (d.montant || 0), 0);
const escapeHtml = (s) => String(s == null ? "" : s).replace(/[&<>"]/g, (c) => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;" }[c]));
// Ouvre une fenêtre d'impression (PDF) avec un document HTML mis en forme.
function openPrint(title, bodyHtml) {
  const w = window.open("", "_blank");
  if (!w) { alert("Autorisez les fenêtres pop-up de ce site pour générer le PDF."); return; }
  w.document.write(`<!doctype html><html lang="fr"><head><meta charset="utf-8"><title>${escapeHtml(title)}</title><style>body{font-family:'Segoe UI',Arial,sans-serif;color:#16203a;padding:30px;max-width:800px;margin:auto;line-height:1.45;}h1{font-size:23px;margin:0 0 2px;}h2{font-size:14px;color:#16203a;border-bottom:2px solid #FF5A45;padding-bottom:4px;margin:24px 0 8px;}table{width:100%;border-collapse:collapse;font-size:12px;margin-top:4px;}th,td{text-align:left;padding:6px 8px;border-bottom:1px solid #eaeef5;}th{color:#5b6478;font-weight:600;font-size:11px;text-transform:uppercase;}.muted{color:#5b6478;font-size:12px;}.stat{display:inline-block;margin:0 22px 6px 0;font-size:12px;}.stat b{display:block;font-size:16px;}.tag{display:inline-block;font-size:11px;background:#eef2fb;border-radius:6px;padding:2px 8px;margin:0 6px 4px 0;}.foot{margin-top:30px;color:#9aa6bd;font-size:10.5px;border-top:1px solid #eaeef5;padding-top:8px;}</style></head><body>${bodyHtml}<div class="foot">PEN'UP 3D · MITMIT · export du ${new Date().toLocaleDateString("fr-FR")}</div><script>window.onload=function(){setTimeout(function(){window.print();},250);}<\/script></body></html>`);
  w.document.close();
}
// Construit le corps HTML d'une fiche (groupe ou établissement) pour l'export PDF.
function ficheBody(title, subtitle, tags, stats, conts, deals, ints, acc) {
  const stat = (stats || []).map((s) => `<span class="stat"><b>${escapeHtml(s.v)}</b>${escapeHtml(s.l)}</span>`).join("");
  const tagH = (tags || []).filter(Boolean).map((t) => `<span class="tag">${escapeHtml(t)}</span>`).join("");
  const cH = conts.length ? `<table><thead><tr><th>Nom</th><th>Fonction</th><th>Rôle</th><th>Courriel</th><th>Téléphone</th></tr></thead><tbody>${conts.map((c) => `<tr><td>${escapeHtml(fullName(c))}${c.principal ? " ★" : ""}</td><td>${escapeHtml(c.fonction)}</td><td>${escapeHtml((ROLE_META[c.role] || {}).label || "")}</td><td>${escapeHtml(c.email)}</td><td>${escapeHtml(c.mobile || c.fixe || "")}</td></tr>`).join("")}</tbody></table>` : `<div class="muted">Aucun contact.</div>`;
  const dH = deals.length ? `<table><thead><tr><th>Réf.</th><th>Type</th><th>Date</th><th>Statut</th><th style="text-align:right">Montant HT</th></tr></thead><tbody>${deals.map((d) => `<tr><td>${escapeHtml(docRef(d, acc))}</td><td>${escapeHtml(d.type)}</td><td>${escapeHtml(d.date)}</td><td>${escapeHtml((DEAL_STATUS[d.statut] || {}).label || d.statut)}</td><td style="text-align:right">${escapeHtml(eur(d.montant))}</td></tr>`).join("")}</tbody></table>` : `<div class="muted">Aucun document.</div>`;
  const iH = ints.length ? `<table><thead><tr><th>Date</th><th>Type</th><th>Sujet</th><th>Résumé</th></tr></thead><tbody>${ints.slice(0, 50).map((i) => `<tr><td>${escapeHtml(i.date)}</td><td>${escapeHtml((INT_META[i.type] || {}).label || i.type)}</td><td>${escapeHtml(i.sujet)}</td><td>${escapeHtml(i.resume || "")}</td></tr>`).join("")}</tbody></table>` : `<div class="muted">Aucun échange.</div>`;
  return `<h1>${escapeHtml(title)}</h1><div class="muted">${escapeHtml(subtitle)}</div><div style="margin-top:8px">${tagH}</div><div style="margin-top:14px">${stat}</div><h2>Contacts</h2>${cH}<h2>Devis, commandes &amp; factures</h2>${dH}<h2>Échanges</h2>${iH}`;
}
// Nombre de jours depuis le dernier échange d'un compte (null si jamais).
function daysSinceLastExchange(accId, data) {
  const ds = (data.interactions || []).filter((i) => i.accountId === accId && i.date).map((i) => i.date).sort();
  if (!ds.length) return null;
  const n = daysFromToday(ds[ds.length - 1]);
  return n == null ? null : Math.max(0, -n);
}
// Score de priorité 0-100 : argent en attente (devis non validés), ancienneté du dernier contact, étape.
function priorityScore(account, data) {
  const caAtt = sumMontant((data.deals || []).filter((d) => d.accountId === account.id && isDevisEnAttente(d)));
  const days = daysSinceLastExchange(account.id, data);
  const stageW = { prospect: 6, contact: 14, rdv: 22, referencement: 28, actif: 10 }[account.stage] || 8;
  let s = Math.min(40, (caAtt / 1000) * 4) + Math.min(35, (days == null ? 30 : days) * 0.6) + stageW;
  s = Math.round(Math.min(100, s));
  const lvl = s >= 60 ? { l: "Élevée", c: "#FF5A45" } : s >= 35 ? { l: "Moyenne", c: "#F8B133" } : { l: "Faible", c: "#9aa6bd" };
  return { score: s, level: lvl.l, color: lvl.c, caAtt, days };
}
// Carte de visite vCard 3.0 d'un contact (téléchargeable / encodable en QR).
function contactVCard(c, account) {
  const org = account ? account.enseigne : "";
  return ["BEGIN:VCARD", "VERSION:3.0", "N:" + (c.nom || "") + ";" + (c.prenom || ""), "FN:" + fullName(c), org ? ("ORG:" + org) : "", c.fonction ? ("TITLE:" + c.fonction) : "", c.email ? ("EMAIL;TYPE=WORK:" + c.email) : "", c.mobile ? ("TEL;TYPE=CELL:" + c.mobile) : "", c.fixe ? ("TEL;TYPE=WORK:" + c.fixe) : "", c.linkedin ? ("URL:" + c.linkedin) : "", c.naissance ? ("BDAY:" + c.naissance) : "", "END:VCARD"].filter(Boolean).join("\r\n");
}
