const TRANCHE_ENDS=[9,19,29,39,49,59,69,79,89,100,299,499,699,999];
const PORT_GAZOLE=0.11, PORT_FIXE=2.24, PORT_PARIS=5.14, PORT_SAISON=0.15;
function shippingCost(dept,kg,opts){opts=opts||{};const arr=DEPT_TARIF[dept];if(!arr||!(kg>0))return null;let i=TRANCHE_ENDS.findIndex(e=>kg<=e);if(i<0)i=TRANCHE_ENDS.length-1;const cent=i>=10;let base,kgF=kg;if(cent){kgF=Math.ceil(kg/10)*10;base=Math.round((kgF/100)*arr[i]*100)/100;}else{base=arr[i];}const r2=(x)=>Math.round(x*100)/100;const gazole=r2(base*PORT_GAZOLE);const saison=opts.saison?r2(base*PORT_SAISON):0;const paris=opts.paris?PORT_PARIS:0;const fixe=PORT_FIXE;const total=r2(base+gazole+saison+paris+fixe);const lbl=i===0?"1 à 9":(i<10?(TRANCHE_ENDS[i-1]+1)+" à "+TRANCHE_ENDS[i]:(i===10?"101 à 299":i===11?"300 à 499":i===12?"500 à 699":"700 à 999"));return{dept,zone:DEPT_ZONES[dept]||"",kg,kgF,trancheLabel:lbl,mode:cent?"aux 100 kg":"forfait",base,gazole,saison,paris,fixe,total};}
function poidsProvisoire(code,designation){const c=(code||"");const d=(designation||"").toLowerCase();if(c.includes("-PACK-COMPLET"))return 0.95;if(c.includes("-PACK-DECOUVERTE"))return 0.65;if(c.includes("-PACK-INITIATION")||c.includes("-PACK-"))return 0.5;if(c.includes("-KIT-"))return 0.55;if(c==="PU3D-STYLO")return 0.12;if(c.includes("-POCHO"))return 0.05;if(c.includes("-LIVRET-"))return 0.18;if(/^PU3D-FIL-/.test(c)){if(/lot de 12|multicolore/.test(d))return 0.36;if(/lot de 4|pastel/.test(d))return 0.12;if(/lot de 3|magique|galaxie|soleil|nature|noir/.test(d))return 0.09;return 0.09;}return 0.1;}
function coefColor(coef, cible, plafond) {
  const R = [255, 90, 69], LG = [118, 204, 152], G = [43, 182, 115], DG = [22, 122, 73];
  const hx = (a) => "#" + a.map((x) => Math.max(0, Math.min(255, Math.round(x))).toString(16).padStart(2, "0")).join("");
  const mix = (a, b, t) => a.map((v, i) => v + (b[i] - v) * Math.max(0, Math.min(1, t)));
  const lowRed = cible - 0.1;
  const mid = (plafond > cible) ? plafond : cible + 0.2;
  const top = (plafond > cible) ? plafond + 0.2 : cible + 0.4;
  if (coef <= lowRed) return hx(R);
  if (coef < cible) return hx(mix(R, LG, (coef - lowRed) / (cible - lowRed)));
  if (coef < mid) return hx(mix(LG, G, (coef - cible) / (mid - cible)));
  if (coef < top) return hx(mix(G, DG, (coef - mid) / (top - mid)));
  return hx(DG);
}
function securedFrom(s) { const spot = (s && s.fxSpot) ? +s.fxSpot : 0.89; const m = (s && s.fxMargin != null) ? +s.fxMargin : 7; return Math.round(spot * (1 + m / 100) * 10000) / 10000; }
function coutRevientParts(code, designation) { const c = (code || "").toUpperCase(); const d = (designation || "").toLowerCase(); if (c.includes("-PACK-COMPLET")) return { usd: 17.64, eur: 0 }; if (c.includes("-PACK-DECOUVERTE")) return { usd: 10.69, eur: 0 }; if (c.includes("-KIT-")) return { usd: 7.34, eur: 0 }; if (c === "PU3D-STYLO") return { usd: 7.14, eur: 0.43 }; if (/^PU3D-FIL-/.test(c)) { if (/lot de 12/.test(d)) return { usd: 3.84, eur: 0 }; if (/lot de 4/.test(d)) return { usd: 1.28, eur: 0 }; return { usd: 0.96, eur: 0 }; } return null; }
function deriveCout(p, secured) { if (p.coutUsd == null) return (p.cout != null ? p.cout : null); return Math.round((p.coutUsd * secured + (p.coutEurFixe || 0)) * 100) / 100; }
const NATURE_META = {
  CA: { label: "Centrale d'achat / groupe", color: "#3F60AA" },
  FC: { label: "Franchisé / franchise", color: "#7c5cf0" },
  MI: { label: "Établissement indépendant", color: "#2bb673" },
  AS: { label: "Association / institution", color: "#F8B133" },
  DI: { label: "Distributeur / grossiste", color: "#FF5A45" },
  DV: { label: "Divers / non classé", color: "#9aa6bd" },
};
const NATURE_ORDER = ["CA", "FC", "MI", "AS", "DI", "DV"];
const FORMES_JURIDIQUES = ["SAS", "SASU", "SARL", "EURL", "SA", "SA coopérative", "SNC", "Société civile (SCI, SCM…)", "Entreprise individuelle (EI)", "Micro-entreprise", "Association loi 1901", "GIE", "Établissement public", "Société monégasque (RCI)"];
// Mappage des comptes du seed initial vers leur nature (pour l'attribution rétroactive)
const SEED_NATURE = { acc_cultura: "CA", acc_kingjouet: "CA", acc_fnac: "CA", acc_joueclub: "CA", acc_eenymeeny: "MI", acc_sourire: "AS" };
const isClientCode = (c) => typeof c === "string" && /^[A-Z]{2}-\d{3,}$/.test(c);
// Devine la nature d'un compte qui n'en a pas encore (seed connu, puis indice typeSurface, sinon DV)
function guessNature(a) {
  if (a.nature && NATURE_META[a.nature]) return a.nature;
  if (SEED_NATURE[a.id]) return SEED_NATURE[a.id];
  const ts = (a.typeSurface || "").toLowerCase();
  if (ts.includes("association") || ts.includes("médiathèque") || ts.includes("mediatheque") || ts.includes("école") || ts.includes("ecole") || ts.includes("loisirs") || ts.includes("crèche") || ts.includes("creche")) return "AS";
  return "DV";
}
// Plus grand numéro déjà utilisé pour un préfixe donné
function maxCodeNum(accounts, prefix) {
  return accounts.reduce((mx, a) => { if (isClientCode(a.code) && a.code.slice(0, 2) === prefix) { const n = parseInt(a.code.split("-")[1], 10); if (n > mx) return n; } return mx; }, 0);
}
// Construit le prochain code client pour une nature, en tenant compte des codes existants
function buildClientCode(accounts, nature) {
  const pfx = NATURE_META[nature] ? nature : "DV";
  return pfx + "-" + String(maxCodeNum(accounts, pfx) + 1).padStart(3, "0");
}
// Attribue un code à tout compte qui n'en a pas, dans l'ordre du tableau, par préfixe (déterministe)
function assignClientCodes(accounts) {
  const counters = {};
  accounts.forEach((a) => { if (isClientCode(a.code)) { const p = a.code.slice(0, 2); const n = parseInt(a.code.split("-")[1], 10); counters[p] = Math.max(counters[p] || 0, n); } });
  return accounts.map((a) => {
    if (isClientCode(a.code)) return a;
    const pfx = NATURE_META[a.nature] ? a.nature : "DV";
    counters[pfx] = (counters[pfx] || 0) + 1;
    return { ...a, code: pfx + "-" + String(counters[pfx]).padStart(3, "0") };
  });
}
