// Nettoie une adresse pour le géocodage : retire BP/CS/Cedex, retours ligne, doublons d'espaces
function cleanAddrForGeo(raw) {
  let s = (raw || "").replace(/[\n\r]+/g, " ");
  s = s.replace(/\bB\.?P\.?\s*\d+\b/gi, " ").replace(/\bC\.?S\.?\s*\d+\b/gi, " ");
  s = s.replace(/\bcedex\b\s*\d*/gi, " ");
  s = s.replace(/[;]+/g, " ").replace(/\s{2,}/g, " ").replace(/^[\s,-]+|[\s,-]+$/g, "").trim();
  return s;
}
// Extrait "code postal + ville" pour un repli sur le centre de la commune
function postcodeCity(raw) {
  const m = (raw || "").match(/\b(\d{5})\b[\s,]*([A-Za-zÀ-ÿ' .-]+?)(?:\s*,|\s+cedex|\s+france|$)/i);
  if (m) return { cp: m[1], ville: (m[2] || "").replace(/cedex.*/i, "").trim() };
  const m2 = (raw || "").match(/\b(\d{5})\b/);
  return m2 ? { cp: m2[1], ville: "" } : null;
}
async function geocodeAdresse(adresseRaw) {
  const adresse = cleanAddrForGeo(adresseRaw) || (adresseRaw || "");
  // 1) BAN sur l'adresse nettoyée (seuil assoupli à 0.35)
  try {
    const r = await fetch("https://api-adresse.data.gouv.fr/search/?limit=1&q=" + encodeURIComponent(adresse));
    if (r.ok) {
      const j = await r.json();
      const f = j.features && j.features[0];
      if (f && (f.properties.score || 0) >= 0.35) {
        const [lng, lat] = f.geometry.coordinates;
        return { lat: Math.round(lat * 1e5) / 1e5, lng: Math.round(lng * 1e5) / 1e5, label: f.properties.label, source: "BAN", approx: (f.properties.score || 0) < 0.55 };
      }
    }
  } catch (e) {}
  // 2) Photon (international) sur l'adresse nettoyée
  try {
    const r = await fetch("https://photon.komoot.io/api/?limit=1&q=" + encodeURIComponent(adresse));
    if (r.ok) {
      const j = await r.json();
      const f = j.features && j.features[0];
      if (f) {
        const [lng, lat] = f.geometry.coordinates;
        const p = f.properties || {};
        const street = p.housenumber && p.street ? p.housenumber + " " + p.street : (p.street || p.name || "");
        const city = p.city || p.town || p.village || p.locality || p.county || "";
        const parts = [street, p.postcode, city, p.country].filter(Boolean);
        return { lat: Math.round(lat * 1e5) / 1e5, lng: Math.round(lng * 1e5) / 1e5, label: parts.join(", ") || (p.name || adresse), source: "Photon/OSM" };
      }
    }
  } catch (e) {}
  // 3) Repli : centre de la commune via code postal + ville (BAN type municipality)
  const pc = postcodeCity(adresseRaw);
  if (pc) {
    try {
      const q = (pc.ville ? pc.ville + " " : "") + pc.cp;
      const r = await fetch("https://api-adresse.data.gouv.fr/search/?limit=1&type=municipality&q=" + encodeURIComponent(q));
      if (r.ok) {
        const j = await r.json();
        const f = j.features && j.features[0];
        if (f) {
          const [lng, lat] = f.geometry.coordinates;
          return { lat: Math.round(lat * 1e5) / 1e5, lng: Math.round(lng * 1e5) / 1e5, label: "Centre commune : " + f.properties.label, source: "BAN", approx: true };
        }
      }
    } catch (e) {}
  }
  return null;
}
// Autocomplétion d'adresses : BAN (France) puis Photon/OSM (international, ex. Monaco). Renvoie label + coordonnées.
async function searchAdresses(q) {
  q = (q || "").trim();
  if (q.length < 3) return [];
  try {
    const r = await fetch("https://api-adresse.data.gouv.fr/search/?limit=6&q=" + encodeURIComponent(q));
    if (r.ok) {
      const j = await r.json();
      const fs = (j.features || []).map((f) => { const [lng, lat] = f.geometry.coordinates; const p = f.properties || {}; return { label: p.label || "", sub: p.context || "", cp: p.postcode || "", ville: p.city || "", lat: Math.round(lat * 1e5) / 1e5, lng: Math.round(lng * 1e5) / 1e5, source: "BAN" }; }).filter((x) => x.label);
      if (fs.length) return fs;
    }
  } catch (e) {}
  try {
    const r = await fetch("https://photon.komoot.io/api/?limit=6&q=" + encodeURIComponent(q));
    if (r.ok) {
      const j = await r.json();
      return (j.features || []).map((f) => { const [lng, lat] = f.geometry.coordinates; const p = f.properties || {}; const street = p.housenumber && p.street ? p.housenumber + " " + p.street : (p.street || p.name || ""); const city = p.city || p.town || p.village || p.locality || ""; const label = [street, p.postcode, city, p.country].filter(Boolean).join(", "); return { label: label || p.name || q, sub: p.country || "", cp: p.postcode || "", ville: city, lat: Math.round(lat * 1e5) / 1e5, lng: Math.round(lng * 1e5) / 1e5, source: "OSM" }; }).filter((x) => x.label);
    }
  } catch (e) {}
  return [];
}
// Rassemble les adresses déjà saisies dans l'outil (établissements, livraisons, prospects) pour réutilisation rapide.
function collectKnownAddresses(data) {
  const out = []; const seen = new Set();
  const push = (label, sub, lat, lng) => { const k = (label || "").trim().toLowerCase(); if (!label || seen.has(k)) return; seen.add(k); out.push({ label: label.trim(), sub: sub || "", lat: lat ?? null, lng: lng ?? null }); };
  (data.sites || []).forEach((s) => { if (s.adresse) push(s.adresse, s.label || "site", s.lat, s.lng); });
  (data.accounts || []).forEach((a) => { if (a.adressePostale) push(a.adressePostale, (a.enseigne || "enseigne"), a.lat, a.lng); if (a.adresseLivraison && a.adresseLivraison !== a.adressePostale) push(a.adresseLivraison, (a.enseigne || "enseigne") + " · livraison", a.lat, a.lng); });
  (data.prospects || []).forEach((p) => { if (p.adresse) push([p.adresse, p.cp, p.ville].filter(Boolean).join(", "), p.nom || "prospect", null, null); });
  return out;
}
