function isGroupe(a) { return a && a.kind ? a.kind === "groupe" : isCentraleOuChaine(a); }
function accountKind(a) { return (a && a.kind) ? a.kind : (isCentraleOuChaine(a) ? "groupe" : "établissement"); }
// Adresse de livraison effective : la postale si "identique", sinon l'adresse de livraison saisie.
