      lat: s.lat ?? primary.lat ?? null, lng: s.lng ?? primary.lng ?? null,
      siret: s.siret || primary.siret || "", typeSurface: s.typeSurface || primary.typeSurface || "",
      photo: s.photo || primary.photo || "", contactId: s.contactId || primary.contactId || "",
