  const att = { ...(p.attachments || {}) };
  if (merge && destSite) { let moved = att[destSite] || []; [accId, ...ownSiteIds].forEach((k) => { if (att[k]) { moved = [...moved, ...att[k]]; delete att[k]; } }); if (moved.length) att[destSite] = moved; }
