  const [structTotal, setStructTotal] = useState(0); const [structVol, setStructVol] = useState(0);
  useEffect(() => { if (loadReq && loadReq.type === "revient") { const d = loadReq.payload || {}; setSelProd(d.selProd || ""); if (d.base != null) setBase(d.base); if (d.ppa != null) setPpa(d.ppa); if (d.logi != null) setLogi(d.logi); if (d.tradePct != null) setTradePct(d.tradePct); if (d.pubPct != null) setPubPct(d.pubPct); if (d.structTotal != null) setStructTotal(d.structTotal); if (d.structVol != null) setStructVol(d.structVol); } }, [loadReq && loadReq.n]);
  const pickProduct = (code) => { setSelProd(code); const p = products.find((x) => x.code === code); if (p) { if (p.cout != null && p.cout > 0) setBase(p.cout); } };
  const memoBase = () => { if (!selProd || !persist) return; persist((pp) => ({ ...pp, products: pp.products.map((x) => x.code === selProd ? { ...x, cout: base } : x) })); };
  const trade = (tradePct / 100) * ppa; const pub = (pubPct / 100) * ppa;
  const struct = structVol > 0 ? structTotal / structVol : 0;
  const full = base + logi + trade + pub + struct;
  const netEur = ppa - full; const netPct = ppa > 0 ? netEur / ppa * 100 : 0;
  const pct = (v) => ppa > 0 ? (v / ppa * 100) : 0;
  const calcPayload = { selProd, base, ppa, logi, tradePct, pubPct, structTotal, structVol };
  const calcDetail = [{ l: "Coût de production", v: eur2(base) }, { l: "Logistique", v: eur2(logi) }, { l: "Trade marketing", v: tradePct + "% · " + eur2(trade) }, { l: "Publicité dédiée", v: pubPct + "% · " + eur2(pub) }, { l: "Frais de structure", v: eur2(struct) }, { l: "Coût de revient complet", v: eur2(full) }, { l: "Prix de cession (PPA)", v: eur2(ppa) }, { l: "Marge nette", v: eur2(netEur) + " · " + netPct.toFixed(1) + "%" }];
  const calcSummary = `Coût complet ${eur2(full)} · PPA ${eur2(ppa)} · marge nette ${eur2(netEur)} (${netPct.toFixed(1)}%)`;
  const col = netPct >= 25 ? "var(--green)" : netPct >= 10 ? "var(--amber)" : "var(--red)";
  const note = netPct >= 25 ? "Marge nette confortable" : netPct >= 10 ? "Marge nette serrée, à surveiller" : netPct >= 0 ? "Marge nette très faible" : "Vente à perte sur ce périmètre";
  const segs = [
    { k: "Coût de production", v: base, c: "#3F60AA" },
    { k: "Logistique", v: logi, c: "#F8B133" },
    { k: "Trade marketing", v: trade, c: "#7c5cf0" },
    { k: "Publicité dédiée", v: pub, c: "#FF5A45" },
    { k: "Frais de structure", v: struct, c: "#9aa6bd" },
    { k: "Marge nette", v: Math.max(0, netEur), c: "#2bb673" },
  ];
  const totalBar = segs.reduce((s, x) => s + x.v, 0) || 1;
