    const r = pvcht; // PVC HT (donc PVC TTC) maintenu constant
    // "eur" : marges égales en euros -> cession = moyenne arithmétique. "rate" : taux de marge égaux -> moyenne géométrique
    const p = mode === "eur" ? (cout + r) / 2 : Math.sqrt(cout * r);
