function FxCalc({ data, persist, loadReq }) {
  const stg = data.settings || {};
  const spot0 = stg.fxSpot != null ? stg.fxSpot : 0.89; const margin0 = stg.fxMargin != null ? stg.fxMargin : 7;
  const [spotIn, setSpotIn] = useState(spot0); const [marginIn, setMarginIn] = useState(margin0); const [busy, setBusy] = useState(false); const [err, setErr] = useState("");
  const securedNow = Math.round(spotIn * (1 + marginIn / 100) * 10000) / 10000;
  const nbCouts = (data.products || []).filter((p) => p.coutUsd != null).length;
  const apply = (spot, marg, source) => { const s = Math.round(spot * 10000) / 10000; persist((d) => { const ns = { ...d.settings, fxSpot: s, fxMargin: marg, fxDate: new Date().toISOString().slice(0, 10), fxSource: source }; const sec = securedFrom(ns); return { ...d, settings: ns, products: d.products.map((p) => p.coutUsd != null ? { ...p, cout: deriveCout(p, sec) } : p) }; }); setSpotIn(s); setMarginIn(marg); };
  const refresh = async () => { setBusy(true); setErr(""); try { const r = await fetch("https://open.er-api.com/v6/latest/USD"); if (!r.ok) throw new Error("HTTP " + r.status); const j = await r.json(); const eur = j && j.rates && j.rates.EUR; if (!eur) throw new Error("réponse inattendue"); apply(+eur, marginIn, "auto"); } catch (e) { setErr("Récupération automatique indisponible ici (" + (e.message || e) + "). Saisissez le cours du jour à la main, puis Appliquer. L'automatique fonctionne dans l'aperçu connecté, ou dans l'application une fois le serveur relais en place."); } finally { setBusy(false); } };
  const [amount, setAmount] = useState(5000); const [rate, setRate] = useState(Math.round((1 / spot0) * 1000) / 1000); const [dir, setDir] = useState("USD_EUR"); const margin = marginIn;
  useEffect(() => { if (loadReq && loadReq.type === "fx") { const d = loadReq.payload || {}; if (d.amount != null) setAmount(d.amount); if (d.rate != null) setRate(d.rate); if (d.dir) setDir(d.dir); } }, [loadReq && loadReq.n]);
  const eurComptant = dir === "USD_EUR" ? amount / rate : amount * rate;
  const secured = dir === "USD_EUR" ? eurComptant * (1 + margin / 100) : eurComptant / (1 + margin / 100);
  const fromCur = dir === "USD_EUR" ? "USD" : "EUR"; const toCur = dir === "USD_EUR" ? "EUR" : "USD";
  const fmt = (n, c) => new Intl.NumberFormat("fr-FR", { style: "currency", currency: c, maximumFractionDigits: 2 }).format(n || 0);
  const calcPayload = { amount, rate, dir };
  const calcDetail = [{ l: "Montant", v: fmt(amount, fromCur) }, { l: "Taux 1 EUR", v: rate + " USD" }, { l: "Au comptant", v: fmt(eurComptant, toCur) }, { l: "Sécurisé (+" + margin + "%)", v: fmt(secured, toCur) }];
  const calcSummary = fmt(amount, fromCur) + " → " + fmt(secured, toCur) + " sécurisé (taux " + rate + ")";
  return (<div style={{ maxWidth: 560 }}>
    <div className="card" style={{ marginBottom: 14 }}><div className="sec-h"><h3 className="pu-display">Cours du jour EUR / USD</h3><span>{stg.fxDate ? "maj " + stg.fxDate : "non daté"}</span></div>
      <div style={{ display: "flex", gap: 10, alignItems: "flex-end", flexWrap: "wrap", marginBottom: 10 }}>
        <div className="fld" style={{ minWidth: 150, flex: 1 }}><label>Spot : 1 $ = ? €</label><input type="number" step="0.0001" value={spotIn} onChange={(e) => setSpotIn(+e.target.value)} /></div>
        <div className="fld" style={{ width: 110 }}><label>Coussin (%)</label><input type="number" step="0.5" value={marginIn} onChange={(e) => setMarginIn(+e.target.value)} /></div>
        <button className="btn btn-g btn-s" onClick={() => apply(spotIn, marginIn, "manuel")}>Appliquer</button>
        <button className="btn btn-p btn-s" onClick={refresh} disabled={busy}><RefreshCw size={14} className={busy ? "spin" : ""} /> {busy ? "…" : "Actualiser"}</button>
      </div>
      <div className="grid" style={{ gridTemplateColumns: "1fr 1fr" }}>
        <div className="calc-out"><span className="l">Spot brut</span><span className="b pu-display tnum">{spotIn} €/$</span><span style={{ fontSize: 11, color: "var(--muted)" }}>soit 1 € = {(spotIn > 0 ? 1 / spotIn : 0).toFixed(4)} $</span></div>
        <div className="calc-out" style={{ background: "#e7f7ef" }}><span className="l">Taux sécurisé (+{marginIn}%)</span><span className="b pu-display tnum" style={{ color: "var(--green)" }}>{securedNow} €/$</span><span style={{ fontSize: 11, color: "var(--muted)" }}>appliqué aux coûts</span></div>
      </div>
      {err && <div className="dup-warn" style={{ marginTop: 10 }}><AlertTriangle size={15} /> {err}</div>}
      <p style={{ fontSize: 11.5, color: "var(--muted)", marginTop: 10, lineHeight: 1.55 }}>Source du dernier cours : <strong>{stg.fxSource || "défaut"}</strong>. « Appliquer » enregistre le cours, calcule le taux sécurisé et recalcule les coûts de revient des {nbCouts} produits chiffrés en dollars. La récupération automatique du cours marche là où le réseau passe ; sinon, saisie manuelle.</p>
    </div>
    <div className="card"><div className="sec-h"><h3 className="pu-display">Convertisseur</h3><span>marge de sécurité {margin}%</span></div>
    <div style={{ display: "flex", gap: 10, alignItems: "flex-end", marginBottom: 12, flexWrap: "wrap" }}><div className="fld" style={{ flex: 1, minWidth: 120 }}><label>Montant ({fromCur})</label><input type="number" step="0.01" value={amount} onChange={(e) => setAmount(+e.target.value)} /></div><button className="iconbtn" title="Inverser le sens" onClick={() => setDir(dir === "USD_EUR" ? "EUR_USD" : "USD_EUR")}><ArrowRightLeft size={16} /></button><div className="fld" style={{ flex: 1, minWidth: 120 }}><label>Taux 1 EUR = ? USD</label><input type="number" step="0.001" value={rate} onChange={(e) => setRate(+e.target.value)} /></div></div>
    <div className="grid" style={{ gridTemplateColumns: "1fr 1fr" }}><div className="calc-out"><span className="l">Au comptant ({toCur})</span><span className="b pu-display tnum">{fmt(eurComptant, toCur)}</span></div><div className="calc-out" style={{ background: "#e7f7ef" }}><span className="l">{dir === "USD_EUR" ? "Budget sécurisé (EUR)" : "Prudent (USD)"}</span><span className="b pu-display tnum" style={{ color: "var(--green)" }}>{fmt(secured, toCur)}</span></div></div>
    <p style={{ fontSize: 11.5, color: "var(--muted)", marginTop: 10 }}>Pour régler une facture JER en USD, budgétez le montant <strong>sécurisé en EUR</strong> (taux comptant + {margin}%), conformément à votre discipline de change.</p>
  </div>
  <SaveCalcBar type="fx" payload={calcPayload} detail={calcDetail} summary={calcSummary} persist={persist} />
  </div>);
}
